#include <stdio.h>
#include <stdlib.h>

int main() {
    int n;
    scanf("%d", &n);
    int *colors = malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        scanf("%d", &colors[i]);
    }
    int cnt = 0;
    int size = n;
    while (size > 0) {
        int mini = colors[0];
        for (int i = 1; i < size; i++) {
            if (colors[i] < mini) {
                mini = colors[i];
            }
        }
        int new_size = 0;
        for (int i = 0; i < size; i++) {
            if (colors[i] % mini != 0) {
                colors[new_size++] = colors[i];
            }
        }
        size = new_size;
        cnt++;
    }
    printf("%d", cnt);
    free(colors);
    return 0;
}
